(window.webpackJsonp=window.webpackJsonp||[]).push([[858],{816:function(s){s.exports=JSON.parse('{"code":["<pre class=\\"hljs\\"><code><span class=\\"hljs-comment\\">/**\\n * <span class=\\"hljs-doctag\\">@param <span class=\\"hljs-type\\">{number[]}</span> <span class=\\"hljs-variable\\">arr</span></span>\\n * <span class=\\"hljs-doctag\\">@param <span class=\\"hljs-type\\">{number}</span> <span class=\\"hljs-variable\\">k</span></span>\\n * <span class=\\"hljs-doctag\\">@return <span class=\\"hljs-type\\">{number}</span></span>\\n */</span>\\n<span class=\\"hljs-keyword\\">var</span> getWinner = <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span>(<span class=\\"hljs-params\\">arr, k</span>) </span>{\\n    <span class=\\"hljs-keyword\\">if</span>(k&gt;=arr.length)<span class=\\"hljs-keyword\\">return</span> <span class=\\"hljs-built_in\\">Math</span>.max.apply(<span class=\\"hljs-built_in\\">Math</span>,arr)\\n    <span class=\\"hljs-keyword\\">let</span> step=<span class=\\"hljs-number\\">0</span>\\n    <span class=\\"hljs-keyword\\">let</span> first=arr.shift()\\n    <span class=\\"hljs-keyword\\">while</span>(arr.length&gt;<span class=\\"hljs-number\\">0</span>){\\n        <span class=\\"hljs-keyword\\">let</span> standby=arr.shift()\\n        <span class=\\"hljs-keyword\\">if</span>(first&gt;standby){\\n            arr.push(standby)\\n            step++\\n        }<span class=\\"hljs-keyword\\">else</span>{\\n            arr.push(first)\\n            first=standby\\n            step=<span class=\\"hljs-number\\">1</span>\\n        }\\n        <span class=\\"hljs-keyword\\">if</span>(step===k){\\n            <span class=\\"hljs-keyword\\">return</span> first\\n        }\\n    }\\n};\\n</code></pre>\\n"],"titleSlug":"find-the-winner-of-an-array-game","hasThinking":false,"content":"<p>\u7ed9\u4f60\u4e00\u4e2a\u7531 <strong>\u4e0d\u540c</strong> \u6574\u6570\u7ec4\u6210\u7684\u6574\u6570\u6570\u7ec4 <code>arr</code> \u548c\u4e00\u4e2a\u6574\u6570 <code>k</code> \u3002</p>\\n\\n<p>\u6bcf\u56de\u5408\u6e38\u620f\u90fd\u5728\u6570\u7ec4\u7684\u524d\u4e24\u4e2a\u5143\u7d20\uff08\u5373 <code>arr[0]</code> \u548c <code>arr[1]</code> \uff09\u4e4b\u95f4\u8fdb\u884c\u3002\u6bd4\u8f83 <code>arr[0]</code> \u4e0e <code>arr[1]</code> \u7684\u5927\u5c0f\uff0c\u8f83\u5927\u7684\u6574\u6570\u5c06\u4f1a\u53d6\u5f97\u8fd9\u4e00\u56de\u5408\u7684\u80dc\u5229\u5e76\u4fdd\u7559\u5728\u4f4d\u7f6e <code>0</code> \uff0c\u8f83\u5c0f\u7684\u6574\u6570\u79fb\u81f3\u6570\u7ec4\u7684\u672b\u5c3e\u3002\u5f53\u4e00\u4e2a\u6574\u6570\u8d62\u5f97 <code>k</code> \u4e2a\u8fde\u7eed\u56de\u5408\u65f6\uff0c\u6e38\u620f\u7ed3\u675f\uff0c\u8be5\u6574\u6570\u5c31\u662f\u6bd4\u8d5b\u7684 <strong>\u8d62\u5bb6</strong> \u3002</p>\\n\\n<p>\u8fd4\u56de\u8d62\u5f97\u6bd4\u8d5b\u7684\u6574\u6570\u3002</p>\\n\\n<p>\u9898\u76ee\u6570\u636e <strong>\u4fdd\u8bc1</strong> \u6e38\u620f\u5b58\u5728\u8d62\u5bb6\u3002</p>\\n\\n<p>&nbsp;</p>\\n\\n<p><strong>\u793a\u4f8b 1\uff1a</strong></p>\\n\\n<pre><strong>\u8f93\u5165\uff1a</strong>arr = [2,1,3,5,4,6,7], k = 2\\n<strong>\u8f93\u51fa\uff1a</strong>5\\n<strong>\u89e3\u91ca\uff1a</strong>\u4e00\u8d77\u770b\u4e00\u4e0b\u672c\u573a\u6e38\u620f\u6bcf\u56de\u5408\u7684\u60c5\u51b5\uff1a\\n<img alt=\\"\\" src=\\"https://assets.leetcode-cn.com/aliyun-lc-upload/uploads/2020/07/30/q-example.png\\" style=\\"height: 90px; width: 400px;\\">\\n\u56e0\u6b64\u5c06\u8fdb\u884c 4 \u56de\u5408\u6bd4\u8d5b\uff0c\u5176\u4e2d 5 \u662f\u8d62\u5bb6\uff0c\u56e0\u4e3a\u5b83\u8fde\u80dc 2 \u56de\u5408\u3002\\n</pre>\\n\\n<p><strong>\u793a\u4f8b 2\uff1a</strong></p>\\n\\n<pre><strong>\u8f93\u5165\uff1a</strong>arr = [3,2,1], k = 10\\n<strong>\u8f93\u51fa\uff1a</strong>3\\n<strong>\u89e3\u91ca\uff1a</strong>3 \u5c06\u4f1a\u5728\u524d 10 \u4e2a\u56de\u5408\u4e2d\u8fde\u7eed\u83b7\u80dc\u3002\\n</pre>\\n\\n<p><strong>\u793a\u4f8b 3\uff1a</strong></p>\\n\\n<pre><strong>\u8f93\u5165\uff1a</strong>arr = [1,9,8,2,3,7,6,4,5], k = 7\\n<strong>\u8f93\u51fa\uff1a</strong>9\\n</pre>\\n\\n<p><strong>\u793a\u4f8b 4\uff1a</strong></p>\\n\\n<pre><strong>\u8f93\u5165\uff1a</strong>arr = [1,11,22,33,44,55,66,77,88,99], k = 1000000000\\n<strong>\u8f93\u51fa\uff1a</strong>99\\n</pre>\\n\\n<p>&nbsp;</p>\\n\\n<p><strong>\u63d0\u793a\uff1a</strong></p>\\n\\n<ul>\\n\\t<li><code>2 &lt;= arr.length &lt;= 10^5</code></li>\\n\\t<li><code>1 &lt;= arr[i] &lt;= 10^6</code></li>\\n\\t<li><code>arr</code> \u6240\u542b\u7684\u6574\u6570 <strong>\u5404\u4e0d\u76f8\u540c</strong> \u3002</li>\\n\\t<li><code>1 &lt;= k &lt;= 10^9</code></li>\\n</ul>\\n","title":"1535. \u627e\u51fa\u6570\u7ec4\u6e38\u620f\u7684\u8d62\u5bb6","relatedTags":["\u6570\u7ec4"],"difficult":"Middle","lang":["javascript"],"uniqueID":"1535"}')}}]);